def gen(rng, size):
    n = max(2, min(size, 100000))
    if rng.random() < 0.6:
        # construct a valid one: root strictly smallest
        rest = [rng.randint(2, 1000) for _ in range(n - 1)]
        arr = [1] + rest
    else:
        arr = [rng.randint(1, 50) for _ in range(n)]
    return [arr]

