from itertools import permutations


class Solution:
    def countPermutations(self, complexity):
        n = len(complexity)
        if n > 8:
            # closed form for large inputs the brute cannot enumerate
            MOD = 10**9 + 7
            if all(complexity[0] < complexity[i] for i in range(1, n)):
                f = 1
                for k in range(1, n):
                    f = f * k % MOD
                return f
            return 0
        MOD = 10**9 + 7
        count = 0
        for perm in permutations(range(n)):
            unlocked = set()
            ok = True
            for idx, comp in enumerate(perm):
                if comp == 0:
                    unlocked.add(0)
                    continue
                enabled = False
                for j in unlocked:
                    if j < comp and complexity[j] < complexity[comp]:
                        enabled = True
                        break
                if not enabled:
                    ok = False
                    break
                unlocked.add(comp)
            if ok:
                count += 1
        return count % MOD

