class Solution:
    def countPermutations(self, complexity):
        MOD = 10**9 + 7
        n = len(complexity)
        root = complexity[0]
        for i in range(1, n):
            if complexity[i] <= root:
                return 0
        result = 1
        for k in range(1, n):
            result = result * k % MOD
        return result

